// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb;

import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.List;
import java.util.Locale;
import java.util.regex.Pattern;
import java.util.stream.Stream;

import org.junit.jupiter.api.Test;

class LmdbEstimatorArchitectureTest {

	private static final int MAX_FACADE_LINES = 500;
	private static final int MAX_IMPLEMENTATION_LINES = 700;
	private static final Pattern QUERY_SPECIFIC_MARKER = Pattern.compile(
			"(?i)(benchmark|test[-_ ]?(iri|uri)|query[-_ ]?(id|name|number)|example\\.(org|com)|getDeclared(Field|Method))");
	private static final List<String> ROOT_IMPLEMENTATIONS = List.of(
			"EstimateEvidenceResolver.java",
			"LmdbAccessCostModel.java",
			"LmdbEstimationEngine.java",
			"LmdbEstimatorRuntime.java",
			"LmdbPropertyPathEstimator.java",
			"LmdbStorageEstimatorEvidence.java");

	@Test
	void estimatorFacadesAreThinAdapters() throws IOException {
		assertLineLimit(source("LmdbEvaluationStatistics.java"), MAX_FACADE_LINES);
		assertLineLimit(source("sketch/SketchBasedJoinEstimator.java"), MAX_FACADE_LINES);
	}

	@Test
	void estimatorImplementationsStaySmallAndNeverReferenceFacades() throws IOException {
		Path estimationRoot = mainJavaRoot().resolve("org/eclipse/rdf4j/sail/lmdb/estimation");
		assertTrue(Files.isDirectory(estimationRoot), "missing unified estimation package: " + estimationRoot);
		try (Stream<Path> files = Files.walk(estimationRoot)) {
			for (Path file : files.filter(path -> path.toString().endsWith(".java")).toList()) {
				assertLineLimit(file, MAX_IMPLEMENTATION_LINES);
				String source = Files.readString(file);
				assertFalse(source.contains("LmdbEvaluationStatistics"),
						() -> file + " points back to the statistics facade");
				assertFalse(source.contains("SketchBasedJoinEstimator"),
						() -> file + " points back to the sketch facade");
			}
		}
		for (String implementation : ROOT_IMPLEMENTATIONS) {
			Path file = source(implementation);
			assertLineLimit(file, MAX_IMPLEMENTATION_LINES);
			assertNoFacadeReference(file);
		}
	}

	@Test
	void evidenceStoresNeverPointBackToEngineOrRuntime() throws IOException {
		String evidence = Files.readString(source("LmdbStorageEstimatorEvidence.java"));
		assertFalse(evidence.contains("LmdbEstimationEngine"), "evidence store points back to engine");
		assertFalse(evidence.contains("LmdbEstimatorRuntime"), "evidence store points back to runtime");

		String engine = Files.readString(source("LmdbEstimationEngine.java"));
		assertFalse(engine.contains("LmdbEstimatorRuntime"), "engine points back to runtime");
	}

	@Test
	void productionEstimatorCodeContainsNoQuerySpecificPatches() throws IOException {
		Path lmdbRoot = mainJavaRoot().resolve("org/eclipse/rdf4j/sail/lmdb");
		try (Stream<Path> files = Files.walk(lmdbRoot)) {
			List<Path> estimatorFiles = files
					.filter(path -> path.toString().endsWith(".java"))
					.filter(LmdbEstimatorArchitectureTest::isEstimatorSource)
					.toList();
			for (Path file : estimatorFiles) {
				String content = Files.readString(file);
				assertFalse(QUERY_SPECIFIC_MARKER.matcher(content).find(),
						() -> "query-specific or reflective marker in " + file);
			}
		}
	}

	@Test
	void estimatorOwnsNoJoinEnumerationAlgorithm() throws IOException {
		Path estimationRoot = mainJavaRoot().resolve("org/eclipse/rdf4j/sail/lmdb/estimation");
		if (!Files.isDirectory(estimationRoot)) {
			return;
		}
		try (Stream<Path> files = Files.walk(estimationRoot)) {
			for (Path file : files.filter(path -> path.toString().endsWith(".java")).toList()) {
				String content = Files.readString(file).toLowerCase(Locale.ROOT);
				assertFalse(content.contains("permutation") || content.contains("enumeratejoin")
						|| content.contains("joinordersearch"),
						() -> "join enumeration belongs to DPhyp, not " + file);
			}
		}
	}

	@Test
	void statisticsFacadeDelegatesJoinOrderingOnlyToDphyp() throws IOException {
		String facade = Files.readString(source("LmdbEvaluationStatistics.java"));
		assertTrue(facade.contains("LmdbHypergraphJoinPlanner.tryPlan("),
				"statistics facade must delegate join ordering to DPhyp");
		assertFalse(facade.contains("new JoinOrderPlanner") || facade.contains("SketchJoinOrderService"),
				"statistics facade must not own an alternative join-order implementation");
	}

	private static boolean isEstimatorSource(Path path) {
		String file = path.getFileName().toString();
		return path.toString().contains("/estimation/")
				|| ROOT_IMPLEMENTATIONS.contains(file)
				|| file.equals("LmdbEvaluationStatistics.java")
				|| file.equals("SketchBasedJoinEstimator.java");
	}

	private static void assertNoFacadeReference(Path file) throws IOException {
		String source = Files.readString(file);
		assertFalse(source.contains("LmdbEvaluationStatistics"), () -> file + " points back to statistics facade");
		assertFalse(source.contains("SketchBasedJoinEstimator"), () -> file + " points back to sketch facade");
	}

	private static void assertLineLimit(Path file, int maximum) throws IOException {
		long lines;
		try (Stream<String> sourceLines = Files.lines(file)) {
			lines = sourceLines.count();
		}
		assertTrue(lines <= maximum, () -> file + " has " + lines + " lines; limit is " + maximum);
	}

	private static Path source(String relativePath) {
		return mainJavaRoot().resolve("org/eclipse/rdf4j/sail/lmdb").resolve(relativePath);
	}

	private static Path mainJavaRoot() {
		Path moduleRoot = Path.of("core/sail/lmdb/src/main/java");
		return Files.isDirectory(moduleRoot) ? moduleRoot : Path.of("src/main/java");
	}
}
